mapper.select:
SELECT /* TODO: 조회 컬럼 나열 */ a.pk_col , a.col1 , a.col2 /* 코드명 서브쿼리 — 코드콤보 표시명 전달 필수 */ , (SELECT comm_cd_nm FROM sy_code_dtl WHERE wrk_tp_cd = '/* TODO */' AND cd_tp_cd = '/* TODO */' AND comm_cd = a.code_cd) AS code_cd_nm , TO_CHAR(a.firs_reg_dts, 'YYYY-MM-DD HH24:MI') AS firs_reg_dts FROM /* TODO: 테이블명 */ a WHERE 1 = 1
AND a.field = #{P_field}
AND a.code_cd = #{P_code_cd}
AND a.dt_col >= REPLACE(#{P_start_dt}, '-', '')
AND a.dt_col <= REPLACE(#{P_end_dt}, '-', '')
ORDER BY a.pk_col DESC

mapper.insert:
/* TODO: PK가 자동 채번인 경우 아래 CTE 패턴 사용 */
WITH gen_id AS (
    SELECT LPAD(
        (COALESCE(
            (SELECT MAX(CAST(pk_col AS BIGINT))
             FROM /* TODO: 테이블명 */
             WHERE pk_col LIKE TO_CHAR(current_timestamp, 'YYYYMMDD') || '%'),
            (TO_CHAR(current_timestamp, 'YYYYMMDD') || '0000')::BIGINT
        ) + 1)::TEXT, 12, '0') AS val
)
INSERT INTO /* TODO: 테이블명 */ (
    pk_col
    , col1
    , col2
    , code_cd
    , rmk
    /* 감사컬럼 — INSERT 시 firs_reg + fina_reg 모두 세팅 */
    , firs_reg_pgm_id
    , firs_reg_dts
    , firs_reg_user_id
    , firs_reg_ip
    , fina_reg_pgm_id
    , fina_reg_dts
    , fina_reg_user_id
    , fina_reg_ip
) VALUES (
    (SELECT val FROM gen_id)
    , #{col1}
    , #{col2}
    , #{code_cd}
    , #{rmk}
    /* 감사컬럼 값 */
    , #{reg_pgm_id}
    , current_timestamp
    , #{login_user_id}
    , #{login_user_ip}
    , #{reg_pgm_id}
    , current_timestamp
    , #{login_user_id}
    , #{login_user_ip}
)

mapper.update:
UPDATE /* TODO: 테이블명 */
SET
    col1 = #{col1}
    , col2 = #{col2}
    , code_cd = #{code_cd}
    , rmk = #{rmk}
    /* 감사컬럼 — UPDATE 시 fina_reg만 갱신 */
    , fina_reg_pgm_id = #{reg_pgm_id}
    , fina_reg_dts = current_timestamp
    , fina_reg_user_id = #{login_user_id}
    , fina_reg_ip = #{login_user_ip}
WHERE pk_col = #{pk_col}
